INSERT INTO public.question_bank_questions (product_slug, bank_type, category, question, options, correct_answer, explanation, sort_order) VALUES
('pro-achiever','study','suitability',E'Which client profile is most suitable for Pro Achiever 3.0?','["A client who may need most of the money within 2 years", "A client with stable income, surplus cash flow, and a long-term investment horizon", "A client looking for guaranteed short-term returns", "A client who wants full liquidity with no fluctuation in value"]'::jsonb,1,E'Pro Achiever 3.0 is generally more suitable for clients who can commit for the long term, have stable income, and are able to tolerate short-term market fluctuations. It is not meant for short-term liquidity needs or guaranteed short-term outcomes.',116),
('pro-achiever','study','suitability',E'Which client is least suitable for Pro Achiever 3.0?','["A young working adult starting early for long-term wealth accumulation", "A parent planning for a child''s future over 15 to 20 years", "A client who expects to use the money for a property down payment in 3 years", "A client with moderate risk tolerance and regular monthly savings"]'::jsonb,2,E'A client with a short-term goal like a property down payment in 3 years is generally less suitable for a long-term regular premium ILP. The adviser should distinguish long-term money from short-term money.',117),
('pro-achiever','study','suitability',E'What is the most important factor when assessing whether Pro Achiever 3.0 is suitable?','["Whether the client qualifies for the highest bonus tier", "Whether the client has friends who already bought the plan", "Whether the client has sufficient time horizon and can sustain premiums comfortably", "Whether the client prefers quarterly updates"]'::jsonb,2,E'Suitability is mainly about whether the client can commit over time and whether the plan fits the client''s goals, time horizon, and affordability. Bonus tier alone should never drive the recommendation.',118),
('pro-achiever','study','suitability',E'A client says, "I don''t like seeing any fluctuations in my money." What is the best interpretation?','["They are highly suitable for Pro Achiever 3.0", "Their expectations may not fit a market-linked product", "They only need a higher premium amount", "They should automatically choose the 20-year option"]'::jsonb,1,E'Because Pro Achiever 3.0 is market-linked, short-term fluctuations are part of the product reality. If a client is uncomfortable with any fluctuation, the adviser should reassess suitability rather than force-fit the plan.',119),
('pro-achiever','study','suitability',E'A client says, "I want to invest, but I''m not sure I can commit every month for years." What is the best adviser response?','["\"That''s okay, commitment doesn''t matter.\"", "\"Then this plan may need to be sized more carefully, or we may need to consider whether it is suitable right now.\"", "\"Just choose the highest bonus tier first.\"", "\"You should borrow from savings to make sure the premiums continue.\""]'::jsonb,1,E'This response is balanced and adviser-like. It does not force the sale and instead checks whether the plan fits the client''s ability to sustain premiums over time.',120),
('pro-achiever','study','suitability',E'Which statement best describes when Pro Achiever 3.0 is suitable?','["It is suitable whenever a client wants any form of investment", "It is suitable when a client has long-term goals and can commit regular premiums without compromising short-term needs", "It is suitable only for high net worth clients", "It is suitable only if the client adds term riders"]'::jsonb,1,E'This is the best overall suitability framing. Pro Achiever 3.0 is not for every investor. It is more appropriate for clients with long-term goals and sustainable cash flow.',121),
('pro-achiever','study','suitability',E'Which client objective is most aligned with Pro Achiever 3.0?','["Parking emergency funds", "Building wealth over the long term through disciplined investing", "Generating guaranteed fixed income next year", "Preparing for a large short-term purchase within 18 months"]'::jsonb,1,E'The product is better aligned to long-term wealth accumulation rather than emergency savings or near-term spending goals.',122),
('pro-achiever','study','suitability',E'A client wants Pro Achiever 3.0 mainly because "the welcome bonus sounds attractive," but has no clear long-term goal. What should the adviser do?','["Proceed immediately because the bonus is enough reason", "Recommend the highest premium possible", "Clarify the client''s objectives and assess whether the plan genuinely fits their goals", "Focus only on closing the case before the client changes their mind"]'::jsonb,2,E'A product should not be recommended based only on an attractive feature such as a bonus. The adviser should first establish purpose, time horizon, and suitability.',123),
('pro-achiever','study','suitability',E'Before recommending Pro Achiever 3.0, what should an adviser confirm about the client''s cash flow?','["That the client can stretch to the highest premium tier", "That the client can sustain the premium without sacrificing essential expenses", "That the client is willing to cancel all other savings plans", "That the client is comfortable using credit if needed"]'::jsonb,1,E'Affordability is a core suitability issue. A sustainable premium is more important than maximizing premium size.',124),
('pro-achiever','study','suitability',E'A client earns $4,000 a month and wants to commit $1,500 monthly to Pro Achiever 3.0. What is the best adviser response?','["Encourage it because higher premium means better discipline", "Advise caution and reassess whether the commitment is too aggressive for the client''s overall budget", "Proceed if the client says they are motivated", "Suggest adding riders to make the plan more worthwhile"]'::jsonb,1,E'An adviser should not simply chase premium size. A large commitment relative to income may create future strain and increase the risk of poor outcomes or early surrender.',125),
('pro-achiever','study','suitability',E'A client says, "I can probably afford it if nothing goes wrong." What should the adviser infer?','["That the plan is clearly affordable", "That affordability may be marginal and should be stress-tested more carefully", "That the client is ready for a higher premium", "That time horizon is no longer important"]'::jsonb,1,E'If affordability depends on everything going perfectly, the commitment may not be comfortable enough. Advisers should recommend based on resilience, not optimism alone.',126),
('pro-achiever','study','suitability',E'Which is the best principle when sizing a Pro Achiever 3.0 recommendation?','["Maximize premium to maximize bonus", "Recommend an amount the client can sustain comfortably over the long term", "Start high and let the client figure it out later", "Use the same premium for all clients of similar age"]'::jsonb,1,E'A good recommendation is one the client can maintain. Sustainability matters more than headline bonus percentages.',127),
('pro-achiever','study','suitability',E'A freelancer with irregular income likes the plan but worries about payment commitment. What is the best suitability response?','["\"Irregular income does not matter.\"", "\"We should be more conservative in sizing this, and make sure you have enough buffer before committing.\"", "\"Just pick the highest tier and use the Premium Pass later.\"", "\"Add more riders to justify the commitment.\""]'::jsonb,1,E'This is a prudent response. It acknowledges income volatility and emphasizes buffer and sustainability.',128),
('pro-achiever','study','suitability',E'A client has no emergency fund and wants to start Pro Achiever 3.0 immediately. What is the best adviser response?','["Proceed because investing early matters most", "Recommend building emergency savings first before committing too much into a long-term plan", "Tell them the plan itself can fully replace an emergency fund", "Use the welcome bonus as the reason to start immediately"]'::jsonb,1,E'Emergency liquidity should generally come before long-term investing commitments. This is one of the clearest suitability filters.',129),
('pro-achiever','study','suitability',E'Which statement best reflects proper liquidity planning?','["All available savings should go into long-term plans for discipline", "Only money not needed for short-term use or emergencies should be committed to a long-term ILP", "Emergency funds are unnecessary if a client has insurance", "Long-term investing should replace all short-term savings"]'::jsonb,1,E'Advisers should teach clients to separate short-term, emergency, and long-term money. This is good planning, not just product selling.',130),
('pro-achiever','study','suitability',E'A client asks, "Should I put all my savings into Pro Achiever 3.0?" What is the best answer?','["\"Yes, that gives you the strongest compounding.\"", "\"No, long-term plans should usually be funded with surplus money after short-term and emergency needs are set aside.\"", "\"Yes, because discipline is more important than liquidity.\"", "\"Only if you choose the 20-year option.\""]'::jsonb,1,E'This teaches proper financial planning. The product should be part of a broader strategy, not a place for all available cash.',131),
('pro-achiever','study','suitability',E'What is the best reason not to recommend Pro Achiever 3.0 for emergency savings?','["Because the client may forget the policy exists", "Because long-term market-linked plans are not designed to serve as immediately accessible emergency funds", "Because emergency savings do not need to earn returns", "Because advisers should never discuss emergencies"]'::jsonb,1,E'Emergency savings and long-term investing serve different purposes. Advisers should clearly separate them.',132),
('pro-achiever','study','suitability',E'Why is time horizon so important when recommending Pro Achiever 3.0?','["Because it determines medical underwriting", "Because longer time horizons better match the nature of regular premium, market-linked investing", "Because it affects only the policy booklet wording", "Because it eliminates all risk automatically"]'::jsonb,1,E'Longer time horizons allow regular investing and dollar cost averaging to play out more meaningfully, while short-term horizons make the product less suitable.',133),
('pro-achiever','study','suitability',E'A client says, "I may need this money for renovation in four years." What is the best adviser response?','["Proceed anyway because four years is long enough", "Clarify that this may not be the right product for money likely needed in that time frame", "Recommend the 20-year option instead", "Tell them market growth should cover the risk"]'::jsonb,1,E'The adviser should not force a long-term product onto a short-to-medium-term goal.',134),
('pro-achiever','study','suitability',E'Which client goal is best aligned with Pro Achiever 3.0?','["Saving for a wedding next year", "Saving for a vacation in two years", "Building a 15- to 20-year education or wealth accumulation fund", "Setting aside monthly bill money"]'::jsonb,2,E'Long-term goals are the best fit for a regular premium ILP.',135),
('pro-achiever','study','suitability',E'A client asks whether Pro Achiever 3.0 is suitable for "short-term market opportunities." What is the best answer?','["Yes, it is ideal for tactical short-term moves", "No, it is better positioned for long-term disciplined investing rather than short-term speculation", "Yes, because fund switching guarantees tactical gains", "No, because clients are not allowed to care about markets"]'::jsonb,1,E'This reinforces the correct behavior and expectation for the product.',136),
('pro-achiever','study','suitability',E'A client says, "I want returns, but I never want to see my value drop." What should the adviser do?','["Promise that the plan will avoid all declines", "Reassess whether the client''s expectations fit a market-linked product", "Recommend a higher premium to offset volatility", "Focus only on the death benefit"]'::jsonb,1,E'An adviser should identify mismatched expectations early instead of glossing over them.',137),
('pro-achiever','study','suitability',E'Which client expectation is least compatible with Pro Achiever 3.0?','["\"I understand market values can fluctuate in the short term.\"", "\"I am comfortable investing consistently over many years.\"", "\"I need guaranteed positive returns every year.\"", "\"I am planning for a long-term goal.\""]'::jsonb,2,E'Guaranteed yearly positive returns are not a suitable expectation for a market-linked product.',138),
('pro-achiever','study','suitability',E'A client is highly risk-averse but still wants to invest for the long term. What is the best adviser response?','["Force a higher-equity allocation for better returns", "Explore whether the product and fund mix can be aligned to the client''s comfort level, or whether another solution is more suitable", "Ignore the risk concern and focus on bonuses", "Tell them all investments are basically the same"]'::jsonb,1,E'Suitability is not only about whether a client wants growth, but whether the structure and risk profile fit the client''s temperament and goals.',139),
('pro-achiever','study','suitability',E'Which client behavior suggests stronger suitability for Pro Achiever 3.0?','["Frequently chasing the hottest short-term idea", "Selling investments whenever markets fall", "Comfort with regular long-term contributions and patience through volatility", "Wanting to monitor the plan daily and react constantly"]'::jsonb,2,E'The product is more aligned with disciplined long-term behavior than reactive short-term behavior.',140),
('pro-achiever','study','suitability',E'A client says, "Whenever markets fall, I panic and want to cash out." What should the adviser do?','["Ignore it because the product has bonuses", "Treat it as a behavioral red flag and educate the client before deciding whether the product is suitable", "Recommend the largest premium possible to force commitment", "Tell the client to avoid asking about risk"]'::jsonb,1,E'Behavior matters. A client who panics in downturns may not be suitable for a market-linked long-term plan unless expectations are reset properly.',141),
('pro-achiever','study','suitability',E'Which statement best reflects healthy investor behavior for Pro Achiever 3.0?','["\"I only invest when markets are clearly going up.\"", "\"I prefer to build steadily over time and avoid making emotional decisions.\"", "\"I want to switch funds every week.\"", "\"I will surrender if the value dips early.\""]'::jsonb,1,E'This behavior is far more aligned with the spirit of long-term regular premium investing.',142),
('pro-achiever','study','suitability',E'When might a buy-term-invest-the-rest approach be more suitable than Pro Achiever 3.0?','["When a client values full flexibility and prefers managing investing separately", "When a client wants more discipline and structure", "When a client likes integrated solutions", "When a client wants adviser-guided long-term planning"]'::jsonb,0,E'A good adviser should be able to acknowledge when an alternative may better fit the client. This builds credibility and reduces force-fitting.',143),
('pro-achiever','study','suitability',E'When might Pro Achiever 3.0 be more suitable than fully DIY investing?','["When a client values structured commitment and may struggle with investing discipline on their own", "When a client wants complete freedom to stop and restart at will without consequences", "When a client wants zero product-related costs", "When a client needs guaranteed returns"]'::jsonb,0,E'This is a balanced distinction: DIY offers flexibility, while Pro Achiever may better suit clients who value structure and consistency.',144),
('pro-achiever','study','suitability',E'When should a pure protection solution be prioritized over Pro Achiever 3.0?','["When the client''s main gap is inadequate insurance protection rather than wealth accumulation", "When the client likes bonus illustrations", "When the client asks about education planning", "When the client prefers to invest over time"]'::jsonb,0,E'If the client''s main need is protection rather than long-term wealth building, the adviser should prioritize the right problem first.',145),
('pro-achiever','study','suitability',E'How is Pro Achiever 3.0 most naturally positioned for a young working adult?','["As a short-term savings account substitute", "As a long-term wealth-building plan that starts early and benefits from time in the market", "As a guaranteed retirement income plan starting next year", "As an emergency cash reserve"]'::jsonb,1,E'For young adults, the strongest fit is long-term compounding and disciplined accumulation.',146),
('pro-achiever','study','suitability',E'How is Pro Achiever 3.0 most naturally positioned for parents with a newborn?','["As a short-term childcare expense fund", "As a long-term education or milestone planning vehicle, if affordability and time horizon support it", "As a replacement for all family emergency savings", "As a mandatory rider-led protection plan"]'::jsonb,1,E'This reflects a realistic long-term planning use case without overstating what the product should do.',147),
('pro-achiever','study','suitability',E'Which client segment is most likely to need extra caution before recommending Pro Achiever 3.0?','["A client with steady income and clear long-term goals", "A client with irregular cash flow and weak emergency reserves", "A client who understands market volatility", "A client who already saves consistently"]'::jsonb,1,E'Irregular cash flow and poor liquidity are two of the biggest reasons to slow down and reassess suitability.',148),
('pro-achiever','study','compliance',E'What is the adviser''s primary responsibility when discussing Pro Achiever 3.0?','["To maximize premium size for better bonus illustrations", "To recommend a solution that is suitable for the client''s needs, budget, and time horizon", "To focus only on product strengths", "To avoid discussing risk unless the client insists"]'::jsonb,1,E'Suitability comes before sales. A strong adviser aligns recommendations with client needs and circumstances.',149),
('pro-achiever','study','compliance',E'Which statement is most appropriate when explaining Pro Achiever 3.0?','["\"This plan is suitable for almost everyone.\"", "\"This can be suitable for the right client, especially if the goals, affordability, and time horizon fit.\"", "\"You should buy this first and think about suitability later.\"", "\"As long as the bonus is attractive, suitability is less important.\""]'::jsonb,1,E'This is balanced, accurate, and compliance-safe. It avoids universal claims.',150),
('pro-achiever','study','compliance',E'A client appears enthusiastic but clearly has weak cash flow and near-term liquidity needs. What is the best response?','["Proceed since enthusiasm is a good sign", "Slow down and explain why the product may not be suitable in its current form", "Increase the premium while motivation is high", "Avoid discussing the liquidity issue"]'::jsonb,1,E'This is what a real adviser should do. Excitement is not the same as suitability.',151),
('pro-achiever','study','compliance',E'Which statement should an adviser avoid?','["\"This is designed for long-term investing.\"", "\"Your fund value can fluctuate.\"", "\"You can put all your money here and use it as your emergency reserve too.\"", "\"We should make sure this fits your overall financial planning.\""]'::jsonb,2,E'That statement promotes poor planning and is unsuitable.',152),
('pro-achiever','study','advisory-skills',E'Before presenting Pro Achiever 3.0, which discovery question is most valuable?','["\"How much can you comfortably commit each month without affecting your emergency fund or short-term goals?\"", "\"Would you prefer the biggest bonus tier?\"", "\"Do you want to start with riders first?\"", "\"Can I show you the illustration before understanding your goals?\""]'::jsonb,0,E'This question helps the adviser assess affordability and suitability before presenting.',153),
('pro-achiever','study','advisory-skills',E'Which question best helps determine whether Pro Achiever 3.0 should be positioned more as wealth accumulation than protection?','["\"What are you hoping this plan will mainly do for you over the next 10 to 20 years?\"", "\"Do you want quarterly statements?\"", "\"Do you like term riders?\"", "\"Should I show you the welcome bonus table first?\""]'::jsonb,0,E'This question uncovers the client''s real intent and helps avoid defaulting to product pitching.',154),
('pro-achiever','study','advisory-skills',E'What is the best first step when a client expresses interest in Pro Achiever 3.0?','["Recommend the highest bonus band immediately", "Clarify the client''s goals, liquidity needs, and commitment comfort", "Lead with surrender charge comparisons", "Push the urgency of buying now"]'::jsonb,1,E'Good advisers diagnose first and prescribe second.',155),
('pro-achiever','study','closing',E'A client says, "I''m interested, but I want to review my budget first." What is the best response?','["\"No problem — let''s review your budget properly and decide on a comfortable amount, if any.\"", "\"You should just start now and think later.\"", "\"Budget is less important than discipline.\"", "\"If you wait, it means you''re not serious.\""]'::jsonb,0,E'This is a mature, pressure-free closing response that keeps the conversation moving while respecting suitability.',156),
('pro-achiever','study','closing',E'A client says, "I like the concept, but I''m not ready today." What is the best next step?','["Pressure them by saying the offer may disappear soon", "Ask what they still need to feel confident, then agree on a specific follow-up", "End the conversation and move on", "Submit first and let them decide later"]'::jsonb,1,E'A good follow-up step is collaborative, specific, and respectful.',157),
('pro-achiever','study','suitability',E'A client has strong income, but also plans to start a business within 18 months. What is the best adviser approach?','["Recommend the maximum premium because income is currently strong", "Consider whether future cash flow uncertainty makes a lower commitment or deferral more appropriate", "Ignore the future business plan because current income is what matters", "Use the welcome bonus as the deciding factor"]'::jsonb,1,E'Suitability should consider future affordability risk, not only present income.',158),
('pro-achiever','study','suitability',E'A client says, "I already invest monthly into ETFs and I''m very disciplined." What is the best adviser mindset?','["Force-fit Pro Achiever 3.0 anyway", "Acknowledge that the client may already have a working structure, then assess whether Pro Achiever adds meaningful value", "Tell the client ETFs are always inferior", "Switch the conversation to riders only"]'::jsonb,1,E'Strong advisers do not assume every client must fit the same recommendation.',159),
('pro-achiever','study','suitability',E'A client wants the plan mainly because a friend bought it and says it''s good. What should the adviser do?','["Proceed, since social proof is enough", "Explain that the recommendation should still depend on the client''s own goals and circumstances", "Recommend the same premium as the friend", "Focus only on the bonus schedule"]'::jsonb,1,E'Suitability is personal. A friend''s purchase should never replace proper fact-finding.',160),
('pro-achiever','study','compliance',E'Which is the most appropriate way to describe Pro Achiever 3.0 to a client?','["\"A solution everyone should have.\"", "\"A long-term, regular premium investment-linked plan that may suit clients with the right goals, budget, and time horizon.\"", "\"A guaranteed way to build wealth.\"", "\"A short-term opportunity to capture bonuses.\""]'::jsonb,1,E'This description is accurate, balanced, and suitability-conscious.',161),
('pro-achiever','study','advisory-skills',E'A client asks, "Can I afford this?" What is the best adviser response?','["\"If you can pay the first month, you can afford it.\"", "\"Let''s look at your monthly surplus, emergency reserves, and existing commitments before deciding.\"", "\"You should start high and adjust later.\"", "\"Affordability matters less than starting early.\""]'::jsonb,1,E'This is the right advisory process. It moves from emotion to actual financial planning.',162),
('pro-achiever','study','suitability',E'A client says, "I want something long term, but I also need to feel flexible." What is the best adviser response?','["\"Then this plan is impossible for you.\"", "\"We should size it in a way that leaves enough room for your short-term flexibility and emergency needs.\"", "\"Flexibility is not important for wealth planning.\"", "\"Just commit more first, then adjust later.\""]'::jsonb,1,E'This response shows how to balance long-term structure with practical life flexibility.',163);